'use client';

import React from 'react';
import styles from './EvaluationGraph.module.css';

interface EvaluationGraphProps {
    snapshots: { evaluation?: number | null; mate?: number | null; turn: 'w' | 'b' }[];
    height?: number;
    className?: string;
}

const MAX_EVAL = 8; // Bounds the graph to +/- 8 pawns

export default React.memo(function EvaluationGraph({ snapshots, height = 60, className = '' }: EvaluationGraphProps) {
    if (!snapshots || snapshots.length === 0) return null;

    let lastValidEval = 0;

    const dataPoints = snapshots.map((snap, index) => {
        let value = 0;
        let isMate = false;

        // UCI Evaluation is from the perspective of the side to move.
        // We normalize it: Positive = White advantage, Negative = Black advantage.
        const multiplier = snap.turn === 'w' ? 1 : -1;

        if (snap.mate !== null && snap.mate !== undefined) {
            // Mate score: + means forced mate for side-to-move, - means getting mated
            value = (snap.mate > 0 ? 10 : -10) * multiplier;
            isMate = true;
            lastValidEval = value;
        } else if (snap.evaluation !== null && snap.evaluation !== undefined) {
            value = snap.evaluation * multiplier;
            lastValidEval = value;
        } else {
            value = lastValidEval;
        }

        const cappedValue = Math.max(-MAX_EVAL, Math.min(MAX_EVAL, value));
        
        // Convert to percentage of the half-height
        const percent = (Math.abs(cappedValue) / MAX_EVAL) * 100;
        const isWhiteAdvantage = value >= 0;

        return {
            index: index + 1,
            value,
            cappedValue,
            percent,
            isWhiteAdvantage,
            isMate,
            rawSnap: snap
        };
    });

    return (
        <div className={`${styles.container} ${className}`} style={{ height: `${height}px` }}>
            <div className={styles.centerLine} />
            {dataPoints.map((dp, i) => (
                <div key={i} className={styles.barContainer}>
                    <div className={styles.barWrapper} style={{ justifyContent: 'flex-end' }}>
                        {dp.isWhiteAdvantage && (
                            <div 
                                className={`${styles.bar} ${styles.barWhite}`} 
                                style={{ height: `${dp.percent}%` }}
                            />
                        )}
                    </div>
                    <div className={styles.barWrapper} style={{ justifyContent: 'flex-start' }}>
                        {!dp.isWhiteAdvantage && (
                            <div 
                                className={`${styles.bar} ${styles.barBlack}`} 
                                style={{ height: `${dp.percent}%` }}
                            />
                        )}
                    </div>
                    
                    <div className={styles.tooltip}>
                        Move {Math.ceil(dp.index / 2)}
                        <br />
                        {dp.isMate ? `M${Math.abs(dp.rawSnap.mate || 0)}` : dp.value > 0 ? `+${dp.value.toFixed(1)}` : dp.value.toFixed(1)}
                    </div>
                </div>
            ))}
        </div>
    );
});
